<template>
  <view v-if="person" class="page-shell">
    <view class="profile-card"><view class="avatar"><u-icon name="server-man" size="36" color="#FFFFFF" /></view><view class="profile-copy"><view class="name-row"><text class="name">{{ person.name }}</text><text class="status">{{ statusMeta.label }}</text></view><text class="meta">{{ person.phone }} · {{ person.workYears }}年从业经验</text><text class="meta">合作关系编号 {{ person.relationId }}</text></view><view class="availability" :class="{ off: !person.available }"><text>{{ person.available ? '可接单' : '不可接单' }}</text></view></view>
    <view class="stats-card"><view><text>{{ person.rating || '--' }}</text><text>综合评分</text></view><view><text>{{ person.completedOrders }}</text><text>完成服务</text></view><view><text>{{ person.currentTaskCount }}</text><text>当前任务</text></view></view>
    <view class="detail-card"><text class="section-title">服务能力</text><view class="detail-row"><text>服务区域</text><text>{{ person.serviceAreas.join('、') || '--' }}</text></view><view class="detail-row"><text>排班概览</text><text>{{ person.scheduleSummary }}</text></view><view class="tag-row"><text v-for="skill in person.skills" :key="skill">{{ skill }}</text></view></view>
    <view class="detail-card"><text class="section-title">资质证书</text><view v-for="certificate in person.certificates" :key="certificate.number" class="certificate"><view><text class="certificate-name">{{ certificate.name }}</text><text class="certificate-meta">{{ certificate.number }} · 有效期至 {{ certificate.validUntil }}</text></view><text class="certificate-status" :class="{ warning: certificate.status === 'EXPIRING' }">{{ certificate.status === 'EXPIRING' ? '即将到期' : '有效' }}</text></view></view>
    <view class="detail-card"><text class="section-title">合作记录</text><view v-for="record in person.records" :key="`${record.action}-${record.time}`" class="record"><view class="dot" /><view><text class="record-title">{{ record.title }}</text><text v-if="record.remark" class="record-remark">{{ record.remark }}</text><text class="record-time">{{ record.time }} · {{ record.operator }}</text></view></view></view>
    <view v-if="person.status !== STATUS.INVITED" class="bottom-bar"><button v-if="person.status === STATUS.ACTIVE" class="danger-button" @click="changeStatus('suspend')">暂停合作</button><button v-if="person.status === STATUS.SUSPENDED" class="primary-button" @click="changeStatus('resume')">恢复合作</button></view>
  </view>
</template>

<script setup>
import { computed, ref } from 'vue'
import { onLoad } from '@dcloudio/uni-app'
import { ROLES } from '@/constants/roles.js'
import { COOPERATION_STATUS as STATUS, getCooperationStatusMeta } from '@/constants/team-status.js'
import { useMerchantTeamStore } from '@/store/merchant-team.js'
import { requireRole } from '@/utils/permission.js'

const teamStore = useMerchantTeamStore()
const relationId = ref(null)
const person = computed(() => teamStore.currentCaregiver)
const statusMeta = computed(() => getCooperationStatusMeta(person.value?.status))
onLoad(async (options) => { if (!requireRole(ROLES.MERCHANT_MEMBER)) return; relationId.value = Number(options.id); await teamStore.fetchCaregiverDetail(relationId.value) })
function changeStatus(action) { const isSuspend = action === 'suspend'; uni.showModal({ title: isSuspend ? '暂停合作' : '恢复合作', content: isSuspend ? '暂停后该护理人员不会出现在派单候选列表中。确认继续吗？' : '恢复后该护理人员可重新进入派单候选列表。', editable: isSuspend, placeholderText: '可填写暂停原因', success: async ({ confirm, content }) => { if (!confirm) return; await teamStore.updateCaregiverStatus(relationId.value, action, content || ''); uni.showToast({ title: isSuspend ? '已暂停合作' : '已恢复合作', icon: 'success' }) } }) }
</script>

<style lang="scss" scoped>
.page-shell { min-height: 100vh; padding: 25rpx $spacing-base 150rpx; background: $page-gradient; }.profile-card { display: flex; align-items: center; gap: 18rpx; min-height: 190rpx; padding: 28rpx; border-radius: 32rpx; color: #fff; background: linear-gradient(135deg,#116b68,#00a89d 55%,#38c6b5); box-shadow: $shadow-float; }.avatar { display: flex; align-items: center; justify-content: center; width: 86rpx; height: 86rpx; border-radius: 28rpx; background: rgba(255,255,255,.18); }.profile-copy { flex: 1; }.name-row { display: flex; align-items: center; gap: 11rpx; }.name { font-size: 34rpx; font-weight: 700; }.status { padding: 5rpx 10rpx; border-radius: $radius-round; background: rgba(255,255,255,.17); font-size: 20rpx; }.meta { display: block; margin-top: 7rpx; font-size: $font-size-xs; opacity: .78; }.availability { padding: 8rpx 13rpx; border-radius: $radius-round; background: rgba(255,255,255,.18); font-size: $font-size-xs; }.availability.off { opacity: .6; }.stats-card { display: grid; grid-template-columns: repeat(3,1fr); margin-top: 18rpx; padding: 24rpx 10rpx; border: $glass-border-soft; border-radius: 25rpx; background: $surface-gradient; text-align: center; }.stats-card text { display: block; }.stats-card text:first-child { color: $text-color; font-size: 34rpx; font-weight: 700; }.stats-card text:last-child { margin-top: 5rpx; color: $text-color-hint; font-size: $font-size-xs; }.detail-card { margin-top: 18rpx; padding: 24rpx; border: $glass-border-soft; border-radius: 27rpx; background: $surface-gradient; box-shadow: $shadow-sm; }.section-title { color: $text-color; font-size: $font-size-md; font-weight: 700; }.detail-row { display: flex; justify-content: space-between; gap: 20rpx; padding: 19rpx 0; border-bottom: 1rpx solid $divider-color; color: $text-color-secondary; font-size: $font-size-sm; }.detail-row text:last-child { color: $text-color; text-align: right; }.tag-row { display: flex; flex-wrap: wrap; gap: 9rpx; margin-top: 18rpx; }.tag-row text { padding: 7rpx 12rpx; border-radius: $radius-round; color: #008d84; background: #e9fbf7; font-size: $font-size-xs; }.certificate { display: flex; align-items: center; justify-content: space-between; gap: 16rpx; margin-top: 16rpx; padding: 17rpx; border-radius: 19rpx; background: $bg-color-grey; }.certificate-name,.certificate-meta { display: block; }.certificate-name { color: $text-color; font-size: $font-size-sm; font-weight: 600; }.certificate-meta { margin-top: 5rpx; color: $text-color-hint; font-size: $font-size-xs; }.certificate-status { flex-shrink: 0; color: #008d84; font-size: $font-size-xs; }.certificate-status.warning { color: $warning-color; }.record { display: flex; gap: 14rpx; padding-top: 19rpx; }.dot { width: 14rpx; height: 14rpx; margin-top: 8rpx; border: 4rpx solid #ccefe9; border-radius: 50%; background: #00a89d; }.record-title,.record-remark,.record-time { display: block; }.record-title { color: $text-color; font-size: $font-size-sm; font-weight: 600; }.record-remark { margin-top: 5rpx; color: $text-color-secondary; font-size: $font-size-xs; }.record-time { margin-top: 5rpx; color: $text-color-disabled; font-size: 21rpx; }.bottom-bar { position: fixed; right: 0; bottom: 0; left: 0; padding: 18rpx $spacing-base calc(18rpx + env(safe-area-inset-bottom)); background: rgba(249,251,255,.95); box-shadow: 0 -6rpx 24rpx rgba(42,91,170,.08); }.danger-button,.primary-button { width: 100%; height: 80rpx; margin: 0; border: 0; border-radius: $radius-round; line-height: 80rpx; }.danger-button { color: $error-color; background: #fff0f1; }.primary-button { color: #fff; background: linear-gradient(135deg,#008d84,#00b8a9); }.danger-button::after,.primary-button::after { border: 0; }
</style>
